/**
 * Area orchestration utilities for tiled analysis.
 *
 * Ported from Python SDK `tiling/orchestrator.py`.
 * Provides payload cloning with per-tile location overrides for
 * location-aware analysis types, and grid extraction from analysis results.
 */

import { LOCATION_ANALYSIS_TYPES } from '../analyses/schemas'
import type { Tile } from './types'
import { TILE_SIZE_CELLS } from './types'

// ---------------------------------------------------------------------------
// Payload cloning
// ---------------------------------------------------------------------------

/**
 * Deep clone an analysis payload and override the location fields
 * with the tile's centroid coordinates.
 *
 * For location-aware analysis types (Solar, SolarRadiation, UTCI/TCI, TCS),
 * the `latitude` and `longitude` fields in the payload are replaced with
 * the tile centroid's values. For non-location types, the payload is
 * returned as a deep clone without location modification.
 *
 * @param payload - The original analysis payload to clone.
 * @param tile - The tile whose centroid provides the location override.
 * @param analysisType - The analysis type name (used to determine if location override is needed).
 * @returns A deep-cloned payload with tile-specific location fields.
 */
export function clonePayloadForTile(
  payload: Record<string, unknown>,
  tile: Tile,
  analysisType: string,
): Record<string, unknown> {
  // Prefer structuredClone (available in modern runtimes) which handles
  // more types than JSON round-trip; fall back to JSON for older environments
  const cloned: Record<string, unknown> =
    typeof structuredClone === 'function'
      ? structuredClone(payload)
      : (JSON.parse(JSON.stringify(payload)) as Record<string, unknown>)

  // Override location for location-aware analysis types
  if (LOCATION_ANALYSIS_TYPES.includes(analysisType)) {
    cloned.latitude = tile.centroid.latitude
    cloned.longitude = tile.centroid.longitude
  }

  return cloned
}

// ---------------------------------------------------------------------------
// Grid extraction
// ---------------------------------------------------------------------------

/**
 * Extract a Float64Array grid from an analysis result object.
 *
 * The analysis API returns results in several formats:
 * - `{ output: number[][] }` — array of arrays (most common)
 * - `{ matrix: number[][] }` — alternative key
 * - `{ data: number[][] }` — another alternative
 *
 * The result is flattened into a row-major Float64Array of shape
 * (TILE_SIZE_CELLS x TILE_SIZE_CELLS). If the grid is smaller than
 * expected, remaining cells are filled with NaN.
 *
 * @param result - The raw analysis result object.
 * @returns A flat Float64Array of shape (TILE_SIZE_CELLS x TILE_SIZE_CELLS).
 * @throws Error if no recognizable grid data is found in the result.
 */
export function extractGrid(result: Record<string, unknown>): Float64Array {
  const expectedSize = TILE_SIZE_CELLS * TILE_SIZE_CELLS
  const grid = new Float64Array(expectedSize)
  grid.fill(NaN)

  // Try to find the grid data under known keys
  const rawGrid = findGridData(result)
  if (rawGrid === null) {
    throw new Error(
      `No grid data found in analysis result. Expected one of: output, matrix, data. ` +
        `Got keys: ${Object.keys(result).join(', ')}`,
    )
  }

  // PWC and similar categorical analyses return string letters (e.g.
  // Lawson criteria: "A", "B", ...) instead of numbers. Numeric strings
  // ("0", "1.5") still parse fine. Pre-0.8.1 the SDK called Number(val)
  // directly, producing NaN for non-numeric strings → empty PWC grids.
  // Python's `_area/_merging.py:243+` falls back to a sorted alphabetical
  // category→index mapping per tile when the float conversion fails.
  // This mirrors that exactly. Per-tile mapping risks cross-tile
  // inconsistency if categories differ (rare in practice for PWC), but
  // matches Python.
  const uniqueCats = new Set<string>()
  let needsCategoricalMap = false
  for (const row of rawGrid) {
    if (!Array.isArray(row)) continue
    for (const val of row) {
      if (val === null || val === undefined || val === '') continue
      if (typeof val === 'string' && Number.isNaN(Number(val))) {
        needsCategoricalMap = true
        uniqueCats.add(val)
      }
    }
  }
  const catMap: Map<string, number> | null = needsCategoricalMap
    ? new Map([...uniqueCats].sort().map((c, i) => [c, i]))
    : null

  // Flatten 2D array into row-major Float64Array
  for (let r = 0; r < rawGrid.length && r < TILE_SIZE_CELLS; r++) {
    const row = rawGrid[r]
    for (let c = 0; c < row.length && c < TILE_SIZE_CELLS; c++) {
      const val = row[c]
      if (val === null || val === undefined || val === '') continue
      const mapped = catMap?.get(val as string)
      if (mapped !== undefined) {
        grid[r * TILE_SIZE_CELLS + c] = mapped
        continue
      }
      const num = Number(val)
      if (!Number.isNaN(num)) {
        grid[r * TILE_SIZE_CELLS + c] = num
      }
    }
  }

  return grid
}

// ---------------------------------------------------------------------------
// Internal helpers
// ---------------------------------------------------------------------------

/**
 * Search for grid data in the result under known keys.
 *
 * Returns the first 2D array found, or null if none is found.
 */
function findGridData(
  result: Record<string, unknown>,
): Array<Array<number | string | null | undefined>> | null {
  // Priority order: output > matrix > data
  // Element type is widened from `number[][]` because categorical analyses
  // (PWC + Lawson criteria) return string letters ("A", "B", ...) per cell.
  // The numeric narrowing was a lie the call site at `extractGrid` already
  // handled at runtime — this just makes the TypeScript signature honest.
  const keys = ['output', 'matrix', 'data']

  for (const key of keys) {
    const value = result[key]
    if (Array.isArray(value) && value.length > 0 && Array.isArray(value[0])) {
      return value as Array<Array<number | string | null | undefined>>
    }
  }

  return null
}
