/**
 * S12a directional smart-blend merger for wind-speed tile grids.
 *
 * 1:1 port of Python `infrared_sdk.tiling.merger_smart`. Drop-in
 * replacement for centre-crop merge when `strategy="directional_blend"`
 * is requested. **Wind-speed only** — directional argmax assumes a
 * single wind vector, so PWC and multi-direction analyses must use the
 * default strategy.
 *
 * Algorithm (S12a):
 *  1. Directional argmax — each cell is won by the tile whose
 *     upstream-extent reliability score is highest.
 *  2. Spread-gated blending — where adjacent tiles disagree
 *     (high `tmax - tmin` per cell), an upstream-biased Gaussian smooth
 *     is mixed in to soften seam artefacts.
 *  3. Building keep-out — cells near NaN (building footprints) keep the
 *     raw directional value; blending is only applied in open areas.
 *
 * Pure TypeScript — no FFT library, no numpy / scipy. The FFT used for
 * the Gaussian convolution is a Cooley-Tukey radix-2 implementation
 * below, matching Python's `np.fft.rfft2` / `np.fft.irfft2`-based
 * `_fftconvolve_same` output to within floating-point summation order.
 */

import type { TilingConfig } from './config'
import type { TileGridEntry } from './merger'

// ---------------------------------------------------------------------------
// Parameters
// ---------------------------------------------------------------------------

/** Tuning parameters for the S12a merger. Mirrors Python `BlendParams`. */
export interface BlendParams {
  /** Meteorological wind-from direction (0 = N, 90 = E, 270 = W). */
  readonly windDirectionDeg: number
  /** Sigmoid slope for upstream-extent reliability ramp (cells). */
  readonly recoveryLengthCells: number
  /**
   * Fractional tile depth at which reliability reaches 50%. Default 0.30
   * places the sigmoid inflection inside the 256-cell overlap strip
   * (`0.30 × 512 = 154` cells from the upstream tile edge).
   */
  readonly handoffOffset: number
  /** Radius of the inscribed-disk falloff (cells). */
  readonly radialInscribedRadius: number
  /** Width of the radial falloff transition zone (cells). */
  readonly radialFalloffCells: number
}

const DEFAULT_BLEND_PARAMS: Omit<BlendParams, 'windDirectionDeg'> = {
  recoveryLengthCells: 96.0,
  handoffOffset: 0.30,
  radialInscribedRadius: 240.0,
  radialFalloffCells: 24.0,
}

function makeParams(windDirectionDeg: number, overrides?: Partial<BlendParams>): BlendParams {
  return {
    ...DEFAULT_BLEND_PARAMS,
    windDirectionDeg,
    ...(overrides ?? {}),
  }
}

// ---------------------------------------------------------------------------
// Geometry helpers
// ---------------------------------------------------------------------------

/**
 * Meteorological compass (wind-from) → tile-array flow unit vector.
 * Row 0 = SOUTH of the polygon (TMS-style); data y-axis points NORTH.
 * Mirrors Python `wind_vector`.
 */
export function windVector(compassDeg: number): [number, number] {
  const theta = (compassDeg * Math.PI) / 180.0
  return [-Math.sin(theta), -Math.cos(theta)]
}

// ---------------------------------------------------------------------------
// Reliability mask construction (pure)
// ---------------------------------------------------------------------------

/**
 * Stable sigmoid (avoids overflow for large negative inputs by branching
 * on sign — same pattern as Python `_sigmoid`).
 */
function sigmoid(x: number): number {
  if (x >= 0) {
    return 1.0 / (1.0 + Math.exp(-x))
  }
  const ex = Math.exp(x)
  return ex / (1.0 + ex)
}

/**
 * Per-cell ray-trace distance (cells) against the wind direction to the
 * tile boundary. Mirrors Python `_base_upstream_extent`.
 *
 * Returns a flat row-major Float32Array of length `ts * ts`.
 */
function baseUpstreamExtent(ts: number, params: BlendParams): Float32Array {
  const [wx, wy] = windVector(params.windDirectionDeg)
  const ux = -wx
  const uy = -wy
  const out = new Float32Array(ts * ts)
  const eps = 1e-6
  const fallback = ts * 2.0

  for (let r = 0; r < ts; r++) {
    const y = r + 0.5
    let ty: number
    if (Math.abs(uy) < eps) ty = fallback
    else if (uy > 0) ty = (ts - y) / uy
    else ty = -y / uy

    for (let c = 0; c < ts; c++) {
      const x = c + 0.5
      let tx: number
      if (Math.abs(ux) < eps) tx = fallback
      else if (ux > 0) tx = (ts - x) / ux
      else tx = -x / ux

      const t = Math.max(Math.min(tx, ty), 0.0)
      out[r * ts + c] = t
    }
  }
  return out
}

/**
 * Reliability score in `[0.01, 1]` per cell. Combines an upstream-extent
 * sigmoid ramp with an optional inscribed-disk radial falloff. Mirrors
 * Python `_tile_reliability_mask`.
 *
 * Returns a flat row-major Float32Array of length `ts * ts`.
 */
function tileReliabilityMask(ts: number, params: BlendParams): Float32Array {
  const tUp = baseUpstreamExtent(ts, params)
  const sigmoidMid = params.handoffOffset * ts
  const out = new Float32Array(ts * ts)

  const useRadial =
    params.radialInscribedRadius > 0 && params.radialFalloffCells > 0
  const half = ts / 2.0

  for (let r = 0; r < ts; r++) {
    const dy = r - half
    for (let c = 0; c < ts; c++) {
      const idx = r * ts + c
      let w = sigmoid((tUp[idx] - sigmoidMid) / params.recoveryLengthCells)
      w = 0.01 + 0.99 * w
      if (useRadial) {
        const dx = c - half
        const radius = Math.sqrt(dx * dx + dy * dy)
        const falloff = Math.min(
          1.0,
          Math.max(
            0.0,
            (params.radialInscribedRadius - radius) / params.radialFalloffCells,
          ),
        )
        w *= falloff
      }
      out[idx] = w
    }
  }
  return out
}

// ---------------------------------------------------------------------------
// Directional argmax merge (full canvas)
// ---------------------------------------------------------------------------

/**
 * Untrimmed directional argmax merge — full canvas before centre-crop.
 * Mirrors Python `_merge_directional`.
 *
 * The reliability mask is hoisted out of the per-tile loop (matches
 * Python 0.4.7 commit `889a376`).
 *
 * @param tileGrids - Per-tile flat Float64Arrays of shape `ts × ts`.
 * @param numRows - Tile grid rows.
 * @param numCols - Tile grid columns.
 * @param config - TilingConfig (`inferenceSizeCells`, `stepCells`).
 * @param params - BlendParams (wind direction etc.).
 * @returns Flat row-major Float64Array of shape `(H, W)` where
 *   `H = numRows * step + (ts - step)`, `W = numCols * step + (ts - step)`.
 */
export function mergeDirectional(
  tileGrids: readonly TileGridEntry[],
  numRows: number,
  numCols: number,
  config: TilingConfig,
  params: BlendParams,
): { grid: Float64Array; height: number; width: number } {
  const ts = config.inferenceSizeCells
  const step = config.stepCells
  const height = numRows * step + (ts - step)
  const width = numCols * step + (ts - step)

  const bestWeight = new Float32Array(height * width)
  bestWeight.fill(-Infinity)
  const out = new Float64Array(height * width)
  out.fill(NaN)

  const tileW = tileReliabilityMask(ts, params)

  for (const entry of tileGrids) {
    const { row, col, grid } = entry
    if (grid.length !== ts * ts) {
      throw new Error(
        `Tile (${row}, ${col}) grid length ${grid.length} != ${ts * ts} ` +
          `(expected ${ts}×${ts})`,
      )
    }
    const r0 = row * step
    const c0 = col * step
    for (let i = 0; i < ts; i++) {
      const outRowBase = (r0 + i) * width + c0
      const tileRowBase = i * ts
      for (let j = 0; j < ts; j++) {
        const v = grid[tileRowBase + j]
        if (!Number.isFinite(v)) continue
        const w = tileW[tileRowBase + j]
        const dst = outRowBase + j
        if (w > bestWeight[dst]) {
          bestWeight[dst] = w
          out[dst] = v
        }
      }
    }
  }

  return { grid: out, height, width }
}

// ---------------------------------------------------------------------------
// Pure-TS FFT (Cooley-Tukey radix-2, in-place, complex) + 2D convolution
// ---------------------------------------------------------------------------

/** Smallest power of 2 ≥ n. */
function nextPow2(n: number): number {
  if (n <= 1) return 1
  return 2 ** Math.ceil(Math.log2(n))
}

/**
 * In-place complex 1-D FFT (Cooley-Tukey radix-2 decimation-in-time).
 * `n = re.length = im.length` must be a power of 2. If `inverse`, also
 * divides by `n` at the end (so `ifft(fft(x)) === x`).
 */
function fft1d(re: Float64Array, im: Float64Array, inverse: boolean): void {
  const n = re.length
  // Bit-reverse permutation
  for (let i = 1, j = 0; i < n; i++) {
    let bit = n >> 1
    for (; (j & bit) !== 0; bit >>= 1) j ^= bit
    j ^= bit
    if (i < j) {
      const tr = re[i]
      const ti = im[i]
      re[i] = re[j]
      im[i] = im[j]
      re[j] = tr
      im[j] = ti
    }
  }
  // Butterfly
  for (let len = 2; len <= n; len <<= 1) {
    const half = len >> 1
    const angle = ((inverse ? 2 : -2) * Math.PI) / len
    const wlRe = Math.cos(angle)
    const wlIm = Math.sin(angle)
    for (let i = 0; i < n; i += len) {
      let wRe = 1.0
      let wIm = 0.0
      for (let k = 0; k < half; k++) {
        const idx1 = i + k
        const idx2 = idx1 + half
        const tRe = wRe * re[idx2] - wIm * im[idx2]
        const tIm = wRe * im[idx2] + wIm * re[idx2]
        re[idx2] = re[idx1] - tRe
        im[idx2] = im[idx1] - tIm
        re[idx1] += tRe
        im[idx1] += tIm
        const newWRe = wRe * wlRe - wIm * wlIm
        wIm = wRe * wlIm + wIm * wlRe
        wRe = newWRe
      }
    }
  }
  if (inverse) {
    for (let i = 0; i < n; i++) {
      re[i] /= n
      im[i] /= n
    }
  }
}

/**
 * 2-D FFT of an (H, W) array stored row-major in `re` + `im`. H and W
 * must each be a power of 2.
 */
function fft2d(
  re: Float64Array,
  im: Float64Array,
  H: number,
  W: number,
  inverse: boolean,
): void {
  // Row FFTs
  const rowRe = new Float64Array(W)
  const rowIm = new Float64Array(W)
  for (let r = 0; r < H; r++) {
    const base = r * W
    for (let c = 0; c < W; c++) {
      rowRe[c] = re[base + c]
      rowIm[c] = im[base + c]
    }
    fft1d(rowRe, rowIm, inverse)
    for (let c = 0; c < W; c++) {
      re[base + c] = rowRe[c]
      im[base + c] = rowIm[c]
    }
  }
  // Column FFTs
  const colRe = new Float64Array(H)
  const colIm = new Float64Array(H)
  for (let c = 0; c < W; c++) {
    for (let r = 0; r < H; r++) {
      colRe[r] = re[r * W + c]
      colIm[r] = im[r * W + c]
    }
    fft1d(colRe, colIm, inverse)
    for (let r = 0; r < H; r++) {
      re[r * W + c] = colRe[r]
      im[r * W + c] = colIm[r]
    }
  }
}

/**
 * 2-D "same"-mode FFT convolution. `a` is `(aH, aW)`; `b` is `(bH, bW)`;
 * output is `(aH, aW)`. Mirrors Python `_fftconvolve_same`: pad both to
 * `nextPow2(aDim + bDim - 1)`, multiply spectra, inverse FFT, then crop
 * the centre `aH × aW`.
 */
function fftConvolveSame(
  a: Float64Array,
  aH: number,
  aW: number,
  b: Float64Array,
  bH: number,
  bW: number,
): Float64Array {
  const fullH = aH + bH - 1
  const fullW = aW + bW - 1
  const padH = nextPow2(fullH)
  const padW = nextPow2(fullW)
  const N = padH * padW

  const aRe = new Float64Array(N)
  const aIm = new Float64Array(N)
  for (let r = 0; r < aH; r++) {
    const src = r * aW
    const dst = r * padW
    for (let c = 0; c < aW; c++) aRe[dst + c] = a[src + c]
  }
  fft2d(aRe, aIm, padH, padW, false)

  const bRe = new Float64Array(N)
  const bIm = new Float64Array(N)
  for (let r = 0; r < bH; r++) {
    const src = r * bW
    const dst = r * padW
    for (let c = 0; c < bW; c++) bRe[dst + c] = b[src + c]
  }
  fft2d(bRe, bIm, padH, padW, false)

  // Pointwise multiply in-place into aRe/aIm
  for (let i = 0; i < N; i++) {
    const re = aRe[i] * bRe[i] - aIm[i] * bIm[i]
    const im = aRe[i] * bIm[i] + aIm[i] * bRe[i]
    aRe[i] = re
    aIm[i] = im
  }
  fft2d(aRe, aIm, padH, padW, true)

  // Centre crop to (aH, aW). Same offsets as numpy's "same" mode:
  // start = (full - s1) // 2.
  const rowStart = Math.floor((fullH - aH) / 2)
  const colStart = Math.floor((fullW - aW) / 2)
  const out = new Float64Array(aH * aW)
  for (let r = 0; r < aH; r++) {
    const src = (rowStart + r) * padW + colStart
    const dst = r * aW
    for (let c = 0; c < aW; c++) out[dst + c] = aRe[src + c]
  }
  return out
}

// ---------------------------------------------------------------------------
// L1 distance to nearest false (4-pass raster scan)
// ---------------------------------------------------------------------------

/**
 * For each `true` cell in `mask`, the L1 distance to the nearest `false`
 * cell. Mirrors Python `_l1_distance_to_false`. Four-pass raster scan.
 */
function l1DistanceToFalse(
  mask: Uint8Array,
  height: number,
  width: number,
): Float64Array {
  const far = height + width + 1
  const dist = new Float64Array(height * width)
  for (let i = 0; i < mask.length; i++) dist[i] = mask[i] ? far : 0
  // L→R
  for (let r = 0; r < height; r++) {
    const base = r * width
    for (let c = 1; c < width; c++) {
      const d = dist[base + c - 1] + 1
      if (d < dist[base + c]) dist[base + c] = d
    }
  }
  // R→L
  for (let r = 0; r < height; r++) {
    const base = r * width
    for (let c = width - 2; c >= 0; c--) {
      const d = dist[base + c + 1] + 1
      if (d < dist[base + c]) dist[base + c] = d
    }
  }
  // T→B
  for (let r = 1; r < height; r++) {
    const base = r * width
    const prev = (r - 1) * width
    for (let c = 0; c < width; c++) {
      const d = dist[prev + c] + 1
      if (d < dist[base + c]) dist[base + c] = d
    }
  }
  // B→T
  for (let r = height - 2; r >= 0; r--) {
    const base = r * width
    const next = (r + 1) * width
    for (let c = 0; c < width; c++) {
      const d = dist[next + c] + 1
      if (d < dist[base + c]) dist[base + c] = d
    }
  }
  return dist
}

// ---------------------------------------------------------------------------
// Upstream-biased Gaussian smooth (NaN-aware)
// ---------------------------------------------------------------------------

interface SmoothOpts {
  sigmaStreamwise: number
  sigmaCrosswind: number
  upstreamShift: number
  kernelLength: number
}

const DEFAULT_SMOOTH: SmoothOpts = {
  sigmaStreamwise: 8.0,
  sigmaCrosswind: 2.0,
  upstreamShift: 6.0,
  kernelLength: 24,
}

/**
 * Anisotropic Gaussian kernel oriented upstream. Streamwise σ is wider
 * than crosswind σ; the peak is offset `upstreamShift` cells upwind so
 * smoothed values are biased toward upwind-tile predictions. Returns a
 * flat row-major Float64Array of shape `(2K+1, 2K+1)` summing to 1.
 */
function buildUpstreamKernel(
  windDirectionDeg: number,
  opts: SmoothOpts,
): { kernel: Float64Array; size: number } {
  const [wx, wy] = windVector(windDirectionDeg)
  const ux = -wx
  const uy = -wy
  const px = -uy
  const py = ux
  const K = opts.kernelLength
  const size = 2 * K + 1
  const kernel = new Float64Array(size * size)
  let total = 0
  for (let r = 0; r < size; r++) {
    const yy = r - K
    for (let c = 0; c < size; c++) {
      const xx = c - K
      const s = xx * ux + yy * uy
      const n = xx * px + yy * py
      const val = Math.exp(
        -((s + opts.upstreamShift) ** 2) / (2 * opts.sigmaStreamwise ** 2) -
          (n * n) / (2 * opts.sigmaCrosswind ** 2),
      )
      kernel[r * size + c] = val
      total += val
    }
  }
  if (total > 0) for (let i = 0; i < kernel.length; i++) kernel[i] /= total
  return { kernel, size }
}

/**
 * NaN-aware Gaussian smoothing shifted UPSTREAM. Mirrors Python
 * `_upstream_biased_smooth`. Cells that are NaN in `canvas` get weight
 * 0 so smoothing never crosses building footprints. Output cells whose
 * neighbourhood received no finite mass remain NaN.
 *
 * @param canvas - Flat row-major Float64Array of shape `(H, W)`.
 */
function upstreamBiasedSmooth(
  canvas: Float64Array,
  H: number,
  W: number,
  windDirectionDeg: number,
  opts: SmoothOpts = DEFAULT_SMOOTH,
): Float64Array {
  const { kernel, size } = buildUpstreamKernel(windDirectionDeg, opts)
  const filled = new Float64Array(H * W)
  const finite = new Float64Array(H * W)
  const isFin = new Uint8Array(H * W)
  for (let i = 0; i < H * W; i++) {
    if (Number.isFinite(canvas[i])) {
      filled[i] = canvas[i]
      finite[i] = 1
      isFin[i] = 1
    }
  }
  const num = fftConvolveSame(filled, H, W, kernel, size, size)
  const den = fftConvolveSame(finite, H, W, kernel, size, size)
  const out = new Float64Array(H * W)
  for (let i = 0; i < H * W; i++) {
    if (!isFin[i]) {
      out[i] = NaN
      continue
    }
    const d = den[i]
    out[i] = d > 1e-9 ? num[i] / Math.max(d, 1e-9) : NaN
  }
  return out
}

// ---------------------------------------------------------------------------
// Streaming spread (tmax - tmin per cell across all overlapping tiles)
// ---------------------------------------------------------------------------

function streamingSpread(
  tileGrids: readonly TileGridEntry[],
  ts: number,
  step: number,
  H: number,
  W: number,
): Float64Array {
  const tmax = new Float64Array(H * W)
  tmax.fill(-Infinity)
  const tmin = new Float64Array(H * W)
  tmin.fill(Infinity)
  const covered = new Uint8Array(H * W)

  for (const entry of tileGrids) {
    const { row, col, grid } = entry
    if (grid.length !== ts * ts) continue
    const r0 = row * step
    const c0 = col * step
    let anyFinite = false
    for (let i = 0; i < ts; i++) {
      const dstBase = (r0 + i) * W + c0
      const srcBase = i * ts
      for (let j = 0; j < ts; j++) {
        const v = grid[srcBase + j]
        if (!Number.isFinite(v)) continue
        anyFinite = true
        const dst = dstBase + j
        if (v > tmax[dst]) tmax[dst] = v
        if (v < tmin[dst]) tmin[dst] = v
        covered[dst] = 1
      }
    }
    if (!anyFinite) continue
  }
  const spread = new Float64Array(H * W)
  for (let i = 0; i < H * W; i++) {
    spread[i] = covered[i] ? tmax[i] - tmin[i] : 0
  }
  return spread
}

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

/** Public options for `mergeTilesSmart`. */
export interface MergeTilesSmartOptions {
  /** Meteorological wind-from direction in degrees. */
  windDirectionDeg: number
  /** Streamwise Gaussian sigma (cells). Default 8. */
  sigmaStreamwise?: number
  /** Crosswind Gaussian sigma (cells). Default 2. */
  sigmaCrosswind?: number
  /** Upstream peak shift (cells). Default 6. */
  upstreamShift?: number
  /** Kernel half-length (cells); kernel is `(2K+1, 2K+1)`. Default 24. */
  kernelLength?: number
  /** Spread (m/s) above which smooth blending is mixed in. Default 0.5. */
  threshold?: number
  /** Cells within this L1 distance of a NaN keep the raw value. Default 3. */
  buildingKeepOut?: number
}

/**
 * Merge wind-speed tile grids with S12a directional smart-blend.
 * Returns the final cropped `(numRows * stepCells, numCols * stepCells)`
 * grid — same shape as the default centre-crop `mergeTiles`.
 *
 * Wind-speed only. Callers must validate `analysisType === 'wind-speed'`
 * before invoking (matches Python `merge_area_jobs:211` guard).
 */
export function mergeTilesSmart(
  tileGrids: readonly TileGridEntry[],
  numRows: number,
  numCols: number,
  config: TilingConfig,
  opts: MergeTilesSmartOptions,
): { grid: Float64Array; height: number; width: number } {
  const ts = config.inferenceSizeCells
  const step = config.stepCells
  const finalH = numRows * step
  const finalW = numCols * step

  if (tileGrids.length === 0) {
    const empty = new Float64Array(finalH * finalW)
    empty.fill(NaN)
    return { grid: empty, height: finalH, width: finalW }
  }

  const params = makeParams(opts.windDirectionDeg)
  const H = numRows * step + (ts - step)
  const W = numCols * step + (ts - step)

  // 1. Streaming spread across all tiles
  const spread = streamingSpread(tileGrids, ts, step, H, W)

  // 2. Directional argmax (full canvas)
  const rawFull = mergeDirectional(tileGrids, numRows, numCols, config, params).grid

  // 3. Upstream-biased smooth (NaN-aware)
  const smooth = upstreamBiasedSmooth(rawFull, H, W, opts.windDirectionDeg, {
    sigmaStreamwise: opts.sigmaStreamwise ?? DEFAULT_SMOOTH.sigmaStreamwise,
    sigmaCrosswind: opts.sigmaCrosswind ?? DEFAULT_SMOOTH.sigmaCrosswind,
    upstreamShift: opts.upstreamShift ?? DEFAULT_SMOOTH.upstreamShift,
    kernelLength: opts.kernelLength ?? DEFAULT_SMOOTH.kernelLength,
  })

  // 4. Building keep-out + disagree blend weights
  const finiteMask = new Uint8Array(H * W)
  for (let i = 0; i < H * W; i++) {
    finiteMask[i] = Number.isFinite(rawFull[i]) ? 1 : 0
  }
  const distNan = l1DistanceToFalse(finiteMask, H, W)
  const keepOut = opts.buildingKeepOut ?? 3
  const threshold = opts.threshold ?? 0.5
  const thrSafe = Math.max(threshold, 1e-6)
  const keepOutDenom = Math.max(keepOut, 1)

  // 5. Linear mix and crop
  const out = new Float64Array(finalH * finalW)
  const offset = Math.floor((ts - step) / 2)
  for (let r = 0; r < finalH; r++) {
    const srcR = (offset + r) * W
    const dstR = r * finalW
    for (let c = 0; c < finalW; c++) {
      const srcIdx = srcR + offset + c
      const raw = rawFull[srcIdx]
      if (!Number.isFinite(raw)) {
        out[dstR + c] = raw
        continue
      }
      const sm = smooth[srcIdx]
      if (!Number.isFinite(sm)) {
        out[dstR + c] = raw
        continue
      }
      const keepOutW = Math.min(
        1.0,
        Math.max(0.0, (distNan[srcIdx] - keepOut) / keepOutDenom),
      )
      const disagreeW = Math.min(1.0, Math.max(0.0, spread[srcIdx] / thrSafe))
      const w = disagreeW * keepOutW
      out[dstR + c] = (1.0 - w) * raw + w * sm
    }
  }
  return { grid: out, height: finalH, width: finalW }
}
