/**
 * Coordinate transformations for building-to-tile assignment.
 *
 * Pure functions that convert building coordinates between polygon-bbox-SW
 * and tile-SW reference frames, and assign buildings to tiles based on
 * bounding-box spatial intersection (with context margin) — mirrors the
 * server-side `turf.intersect()` behaviour so a building straddling a
 * tile boundary lands in every tile it overlaps, with full unclipped
 * geometry. Ported from Python SDK `tiling/transforms.py`.
 *
 * Coordinates are flat `[x, y, z, x, y, z, ...]` — stride 3 per vertex.
 */

import type { Tile } from './types'
import { WIND_TILING_CONFIG, type TilingConfig } from './config'

// ---------------------------------------------------------------------------
// Tile geometry helpers
// ---------------------------------------------------------------------------

/**
 * SW-corner offset of a tile relative to the polygon-bbox SW corner (meters).
 * Mirrors Python `tile_sw_offset(row, col, config)`.
 */
export function tileSwOffset(
  row: number,
  col: number,
  config: TilingConfig = WIND_TILING_CONFIG,
): [number, number] {
  const offsetX = (col + 0.5) * config.stepM - config.inferenceSizeM / 2.0
  const offsetY = (row + 0.5) * config.stepM - config.inferenceSizeM / 2.0
  return [offsetX, offsetY]
}

// ---------------------------------------------------------------------------
// Building coordinate helpers
// ---------------------------------------------------------------------------

/** Compute the (x, y) centroid of a flat coordinate array. */
export function computeBuildingCentroid(
  coords: Float64Array | readonly number[],
): [number, number] {
  const numVertices = Math.floor(coords.length / 3)
  if (numVertices === 0) return [0, 0]

  let sumX = 0
  let sumY = 0
  for (let i = 0; i < numVertices; i++) {
    sumX += coords[i * 3]
    sumY += coords[i * 3 + 1]
  }
  return [sumX / numVertices, sumY / numVertices]
}

/** Axis-aligned (x, y) bounding box of a flat coordinate array. */
export function computeBuildingBbox(
  coords: readonly number[] | Float64Array,
): [number, number, number, number] {
  if (coords.length === 0) {
    throw new Error('Cannot compute bbox of an empty coordinate array')
  }
  if (coords.length % 3 !== 0) {
    throw new Error(`Coordinate array length ${coords.length} is not a multiple of 3`)
  }

  let minX = coords[0]
  let minY = coords[1]
  let maxX = coords[0]
  let maxY = coords[1]
  const numVertices = coords.length / 3
  for (let i = 1; i < numVertices; i++) {
    const x = coords[i * 3]
    const y = coords[i * 3 + 1]
    if (x < minX) minX = x
    if (x > maxX) maxX = x
    if (y < minY) minY = y
    if (y > maxY) maxY = y
  }
  return [minX, minY, maxX, maxY]
}

/**
 * Shift a flat coordinate array from polygon-bbox-SW to tile-SW frame by
 * subtracting `(offsetX, offsetY)` from each (x, y) pair. Z is preserved.
 *
 * Returns a new array — input is not mutated. Mirrors Python
 * `transform_building_coords(coordinates, offset_x, offset_y)`.
 */
export function transformBuildingCoords(
  coords: readonly number[] | Float64Array,
  offsetX: number,
  offsetY: number,
): number[] {
  if (coords.length % 3 !== 0) {
    throw new Error(`Coordinate array length ${coords.length} is not a multiple of 3`)
  }
  const out = new Array<number>(coords.length)
  const numVertices = coords.length / 3
  for (let i = 0; i < numVertices; i++) {
    out[i * 3] = coords[i * 3] - offsetX
    out[i * 3 + 1] = coords[i * 3 + 1] - offsetY
    out[i * 3 + 2] = coords[i * 3 + 2]
  }
  return out
}

// ---------------------------------------------------------------------------
// Building-to-tile assignment
// ---------------------------------------------------------------------------

/** Internal: cached per-tile bounds in polygon-bbox-SW meters. */
interface TileBound {
  tileId: string
  ctxSwX: number
  ctxSwY: number
  ctxNeX: number
  ctxNeY: number
  infSwX: number
  infSwY: number
}

/** Loose dict shape Python uses — buildings are arbitrary key-value bags with `coordinates`. */
export type BuildingData = { coordinates?: readonly number[]; [k: string]: unknown }

/**
 * Assign buildings to all tiles whose context bbox overlaps the building bbox.
 *
 * For each building, computes its axis-aligned bbox in polygon-bbox-SW meters
 * and places it in **every** tile whose context bbox (inference bbox plus
 * `contextMarginM`) intersects that bbox. A building straddling a tile
 * boundary lands in all adjacent tiles with its full unclipped geometry —
 * mirrors server-side `turf.intersect()`.
 *
 * Coordinates are deep-copied per tile and translated to that tile's SW frame.
 *
 * Mirrors Python `assign_buildings_to_tiles` 1:1.
 *
 * @param buildings - Flat `{building_id: data}` dict. Each value must have
 *   a `coordinates` field with a stride-3 flat number array.
 * @param tiles - Non-empty tiles as `{row, col, tile}` (e.g. from `getNonEmptyTiles`).
 * @param opts.config - Tiling config (wind / solar). Defaults to wind.
 * @param opts.strict - When true, throw on invalid coordinates instead of skipping.
 * @returns `{tileId: {building_id: data}}` map. Coords in tile-SW frame.
 *   Buildings outside all tiles are silently dropped.
 */
export function assignBuildingsToTiles(
  buildings: Readonly<Record<string, BuildingData>>,
  tiles: ReadonlyArray<{ row: number; col: number; tile: Tile }>,
  opts: { config?: TilingConfig; strict?: boolean } = {},
): Record<string, Record<string, BuildingData>> {
  const config = opts.config ?? WIND_TILING_CONFIG
  const margin = (config.contextSizeM - config.inferenceSizeM) / 2.0

  const tileBounds: TileBound[] = tiles.map(({ row, col, tile }) => {
    const [swX, swY] = tileSwOffset(row, col, config)
    return {
      tileId: tile.tileId,
      ctxSwX: swX - margin,
      ctxSwY: swY - margin,
      ctxNeX: swX + config.inferenceSizeM + margin,
      ctxNeY: swY + config.inferenceSizeM + margin,
      infSwX: swX,
      infSwY: swY,
    }
  })

  const result: Record<string, Record<string, BuildingData>> = {}
  for (const { tile } of tiles) result[tile.tileId] = {}

  for (const [bldgKey, bldgData] of Object.entries(buildings)) {
    const coords = bldgData?.coordinates
    if (!Array.isArray(coords) && !(coords instanceof Float64Array)) {
      const msg = `Building ${JSON.stringify(bldgKey)}: missing or non-sequence coordinates`
      if (opts.strict) throw new Error(msg)
      continue
    }
    if (coords.length === 0 || coords.length % 3 !== 0) {
      const msg = `Building ${JSON.stringify(bldgKey)}: empty or invalid coordinates`
      if (opts.strict) throw new Error(msg)
      continue
    }

    const [bMinX, bMinY, bMaxX, bMaxY] = computeBuildingBbox(coords)

    for (const tb of tileBounds) {
      if (
        bMinX < tb.ctxNeX &&
        bMaxX > tb.ctxSwX &&
        bMinY < tb.ctxNeY &&
        bMaxY > tb.ctxSwY
      ) {
        // Deep-copy the building and shift coords into the tile-SW frame.
        const entry: BuildingData = { ...bldgData }
        entry.coordinates = transformBuildingCoords(coords, tb.infSwX, tb.infSwY)
        result[tb.tileId][bldgKey] = entry
      }
    }
  }

  return result
}
