/**
 * Concurrent tile executor with concurrency limiting, retry, and progress tracking.
 *
 * Ported from Python SDK `tiling/executor.py`.
 * Uses `p-limit` + `Promise.allSettled` instead of Python's ThreadPoolExecutor.
 * Provides progress tracking via both callback and mitt EventEmitter.
 *
 * Note: Python uses `threading.local()` for per-thread HTTP sessions --
 * TS doesn't need this since fetch is inherently concurrent.
 */

import mitt from 'mitt'
import pLimit from 'p-limit'

import type { TileEvents, TileFailure, TileProgress } from './types'

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------

/** Default maximum number of concurrent tile operations. */
const DEFAULT_MAX_WORKERS = 20

/** Default number of retries per tile. */
const DEFAULT_MAX_RETRIES = 2

/** Default per-tile timeout in milliseconds. */
const DEFAULT_TILE_TIMEOUT_MS = 180_000 // 3 minutes

/** Default total timeout in milliseconds. */
const DEFAULT_TOTAL_TIMEOUT_MS = 600_000 // 10 minutes

/** Base delay for exponential backoff in milliseconds. */
const RETRY_BACKOFF_BASE_MS = 1000

/** Maximum backoff delay in milliseconds. */
const RETRY_BACKOFF_CAP_MS = 10_000

// ---------------------------------------------------------------------------
// Timeout error
// ---------------------------------------------------------------------------

/**
 * Dedicated error type for timeout rejections from `raceTimeout`.
 *
 * Allows callers to distinguish timeouts from other errors without
 * relying on string matching.
 */
class TileTimeoutError extends Error {
  constructor(message: string) {
    super(message)
    this.name = 'TileTimeoutError'
  }
}

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/** Configuration for the tile executor. */
export interface TileExecutorConfig {
  /** Maximum number of concurrent tile operations. Default: 20. Must be >= 1. */
  maxWorkers?: number
  /** Maximum number of retries per tile on failure. Default: 2. Must be >= 0. */
  maxRetries?: number
  /** Per-tile timeout in milliseconds. Default: 180000 (3 minutes). Must be > 0. */
  tileTimeoutMs?: number
  /** Total timeout for all tiles in milliseconds. Default: 600000 (10 minutes). Must be > 0. */
  totalTimeoutMs?: number
  /** Base delay for retry backoff in milliseconds. Default: 1000. */
  retryBackoffBaseMs?: number
  /** Maximum retry backoff delay in milliseconds. Default: 10000. */
  retryBackoffCapMs?: number
  /** Callback fired on every tile progress update. */
  onProgress?: (progress: TileProgress) => void
}

/** Description of a tile operation to execute. */
export interface TileJob<T = Record<string, unknown>> {
  readonly tileId: string
  readonly row: number
  readonly col: number
  /** The async function to execute for this tile. */
  readonly execute: (signal: AbortSignal) => Promise<T>
}

/** Result of executing a single tile job. */
export interface TileJobResult<T = Record<string, unknown>> {
  readonly tileId: string
  readonly row: number
  readonly col: number
  readonly success: boolean
  readonly result?: T
  readonly error?: string
  readonly exception?: Error
}

/** Aggregated result from a tile execution run. */
export interface ExecutionResult<T = Record<string, unknown>> {
  readonly results: readonly TileJobResult<T>[]
  readonly failures: readonly TileFailure[]
  readonly completedCount: number
  readonly failedCount: number
  readonly totalCount: number
  readonly executionTime: number
  /** True when execution was cut short by the total timeout. */
  readonly timedOut: boolean
}

/**
 * Mutable execution context shared between execute() and its child jobs.
 * The `closed` flag prevents late-finishing jobs from mutating results
 * or emitting events after execute() has returned.
 */
interface ExecutionContext<T> {
  closed: boolean
  completedCount: number
  failedCount: number
  readonly collectedResults: TileJobResult<T>[]
}

// ---------------------------------------------------------------------------
// TileExecutor
// ---------------------------------------------------------------------------

/**
 * Concurrent tile executor with configurable concurrency, retry, and timeout.
 *
 * Both per-tile and total timeouts are enforced via `Promise.race` so that
 * even jobs that ignore the AbortSignal are guaranteed to time out.
 *
 * On total timeout, partial results from tiles that already completed are
 * preserved. Tiles still in-flight are marked as failed with a timeout error.
 *
 * Timeout errors (`TileTimeoutError`) are not retried because the underlying
 * job may still be running in the background (it ignores AbortSignal),
 * and retrying would cause duplicate concurrent executions.
 *
 * Event handlers and onProgress callbacks are wrapped in try/catch so
 * observer errors never change tile execution semantics. Once execution
 * is `closed` (after execute() returns), no further events are emitted.
 *
 * Usage:
 * ```ts
 * const executor = new TileExecutor({ maxWorkers: 10 })
 * executor.on('tile.completed', ({ tileId }) => console.log(`Done: ${tileId}`))
 * const result = await executor.execute(jobs)
 * ```
 */
export class TileExecutor<T = Record<string, unknown>> {
  private readonly maxWorkers: number
  private readonly maxRetries: number
  private readonly tileTimeoutMs: number
  private readonly totalTimeoutMs: number
  private readonly retryBackoffBaseMs: number
  private readonly retryBackoffCapMs: number
  private readonly onProgress?: (progress: TileProgress) => void
  private readonly emitter = mitt<TileEvents>()

  constructor(config: TileExecutorConfig = {}) {
    const maxWorkers = config.maxWorkers ?? DEFAULT_MAX_WORKERS
    const maxRetries = config.maxRetries ?? DEFAULT_MAX_RETRIES
    const tileTimeoutMs = config.tileTimeoutMs ?? DEFAULT_TILE_TIMEOUT_MS
    const totalTimeoutMs = config.totalTimeoutMs ?? DEFAULT_TOTAL_TIMEOUT_MS

    if (maxWorkers < 1) {
      throw new Error(`maxWorkers must be >= 1, got ${maxWorkers}`)
    }
    if (maxRetries < 0) {
      throw new Error(`maxRetries must be >= 0, got ${maxRetries}`)
    }
    if (tileTimeoutMs <= 0) {
      throw new Error(`tileTimeoutMs must be > 0, got ${tileTimeoutMs}`)
    }
    if (totalTimeoutMs <= 0) {
      throw new Error(`totalTimeoutMs must be > 0, got ${totalTimeoutMs}`)
    }

    this.maxWorkers = maxWorkers
    this.maxRetries = maxRetries
    this.tileTimeoutMs = tileTimeoutMs
    this.totalTimeoutMs = totalTimeoutMs
    this.retryBackoffBaseMs = config.retryBackoffBaseMs ?? RETRY_BACKOFF_BASE_MS
    this.retryBackoffCapMs = config.retryBackoffCapMs ?? RETRY_BACKOFF_CAP_MS
    this.onProgress = config.onProgress
  }

  /** Subscribe to tile execution events. */
  on<K extends keyof TileEvents>(event: K, handler: (data: TileEvents[K]) => void): void {
    this.emitter.on(event, handler)
  }

  /** Unsubscribe from tile execution events. */
  off<K extends keyof TileEvents>(event: K, handler: (data: TileEvents[K]) => void): void {
    this.emitter.off(event, handler)
  }

  /**
   * Execute all tile jobs concurrently with concurrency limiting.
   *
   * Each job is retried up to `maxRetries` times with exponential backoff.
   * Timeout errors are never retried (the hung job may still be running).
   *
   * If the total timeout elapses, remaining jobs are aborted and the
   * partial results collected so far are returned (with `timedOut: true`).
   * The returned result is a snapshot -- late-finishing jobs cannot mutate it
   * and no further events are emitted after execute() returns.
   *
   * @param jobs - Array of tile jobs to execute.
   * @returns Aggregated execution result. Check `timedOut` to detect partial results.
   */
  async execute(jobs: readonly TileJob<T>[]): Promise<ExecutionResult<T>> {
    const startTime = performance.now()
    const limit = pLimit(this.maxWorkers)
    const totalCount = jobs.length

    const ctx: ExecutionContext<T> = {
      closed: false,
      completedCount: 0,
      failedCount: 0,
      collectedResults: [],
    }

    // Total timeout controller -- abort is triggered from the catch block
    // after raceTimeout rejects, not via a parallel setTimeout.  This avoids
    // a race where the abort signal resolves in-flight jobs before raceTimeout
    // has a chance to fire.
    const totalController = new AbortController()

    try {
      const promises = jobs.map((job) =>
        limit(() => this.executeWithRetry(job, totalController.signal, ctx, totalCount, startTime)),
      )

      // Race allSettled against total timeout to guarantee we never hang
      await raceTimeout(
        Promise.allSettled(promises),
        this.totalTimeoutMs,
        'Total execution timeout exceeded',
      )

      // Freeze and return a snapshot
      ctx.closed = true
      return this.buildResult([...ctx.collectedResults], totalCount, startTime, false)
    } catch (error) {
      // Only catch TileTimeoutError (from raceTimeout). Rethrow all others.
      if (!(error instanceof TileTimeoutError)) {
        throw error
      }

      // Total timeout: freeze first (no more events), then abort remaining jobs
      ctx.closed = true
      totalController.abort()

      // Snapshot the results collected so far
      const snapshot = [...ctx.collectedResults]

      // Mark jobs that never finished as failed
      const finishedTileIds = new Set(snapshot.map((r) => r.tileId))
      for (const job of jobs) {
        if (!finishedTileIds.has(job.tileId)) {
          snapshot.push({
            tileId: job.tileId,
            row: job.row,
            col: job.col,
            success: false,
            error: 'Total timeout exceeded',
          })
        }
      }

      return this.buildResult(snapshot, totalCount, startTime, true)
    }
  }

  // -- Private helpers -------------------------------------------------------

  /** Build an ExecutionResult from the collected per-tile results. */
  private buildResult(
    results: TileJobResult<T>[],
    totalCount: number,
    startTime: number,
    timedOut: boolean,
  ): ExecutionResult<T> {
    const failures: TileFailure[] = []
    for (const result of results) {
      if (!result.success) {
        failures.push({
          tileId: result.tileId,
          row: result.row,
          col: result.col,
          error: result.error ?? 'Unknown error',
          exception: result.exception,
        })
      }
    }

    return {
      results,
      failures,
      completedCount: results.filter((r) => r.success).length,
      failedCount: failures.length,
      totalCount,
      executionTime: (performance.now() - startTime) / 1000,
      timedOut,
    }
  }

  /**
   * Execute a single tile job with retry and per-tile timeout.
   *
   * Per-tile timeout is enforced via `Promise.race` so that even jobs
   * ignoring the AbortSignal are guaranteed to time out.
   *
   * Timeout errors (`TileTimeoutError`) are never retried because the
   * hung job may still be running in the background, and retrying would
   * cause duplicate concurrent executions with potential side effects.
   *
   * All event emissions and progress callbacks are gated on `ctx.closed`
   * to prevent events after execute() has returned.
   */
  private async executeWithRetry(
    job: TileJob<T>,
    totalSignal: AbortSignal,
    ctx: ExecutionContext<T>,
    totalCount: number,
    startTime: number,
  ): Promise<TileJobResult<T>> {
    let lastError: Error | undefined

    for (let attempt = 0; attempt <= this.maxRetries; attempt++) {
      // Check total timeout before starting
      if (totalSignal.aborted || ctx.closed) {
        const result: TileJobResult<T> = {
          tileId: job.tileId,
          row: job.row,
          col: job.col,
          success: false,
          error: 'Total timeout exceeded',
        }
        this.recordResult(ctx, result, false, job, totalCount, startTime)
        return result
      }

      // Emit started event (gated on ctx.closed)
      if (attempt === 0) {
        if (!ctx.closed) {
          this.safeEmit('tile.started', {
            tileId: job.tileId,
            row: job.row,
            col: job.col,
          })
        }
      } else {
        const delay = this.computeRetryDelay(attempt)
        if (!ctx.closed) {
          this.safeEmit('tile.retrying', {
            tileId: job.tileId,
            row: job.row,
            col: job.col,
            attempt,
            delay,
          })
        }
        await sleep(delay)
      }

      // Per-tile AbortController chained to total signal.
      // No separate setTimeout here -- raceTimeout provides the single
      // authoritative timer.  On timeout, we call tileController.abort()
      // *after* raceTimeout rejects, which avoids the race where an early
      // abort resolves the job before the timeout fires.
      const tileController = new AbortController()

      // Abort tile if total signal fires
      const totalAbortHandler = () => tileController.abort()
      totalSignal.addEventListener('abort', totalAbortHandler, { once: true })

      try {
        // Race the job execution against a hard per-tile timeout.
        // This guarantees timeout even if the job ignores the AbortSignal.
        const value = await raceTimeout(
          job.execute(tileController.signal),
          this.tileTimeoutMs,
          `Tile ${job.tileId} timed out after ${this.tileTimeoutMs}ms`,
        )

        if (!ctx.closed) {
          this.safeEmit('tile.completed', {
            tileId: job.tileId,
            row: job.row,
            col: job.col,
            result: value as Record<string, unknown>,
          })
        }

        const result: TileJobResult<T> = {
          tileId: job.tileId,
          row: job.row,
          col: job.col,
          success: true,
          result: value,
        }
        this.recordResult(ctx, result, true, job, totalCount, startTime)
        return result
      } catch (error) {
        // On timeout, signal the job to abort (best-effort cleanup).
        // This is done here rather than via a parallel setTimeout to avoid
        // a race where the abort resolves the job before raceTimeout fires.
        if (error instanceof TileTimeoutError) {
          tileController.abort()
        }

        lastError = error instanceof Error ? error : new Error(String(error))

        // Never retry timeout errors: the hung job may still be running in
        // the background, and retrying would cause duplicate concurrent
        // executions with potential side effects.
        const isTimeout = error instanceof TileTimeoutError
        if (!isTimeout && attempt < this.maxRetries) {
          // Will retry non-timeout errors
          continue
        }

        // Final attempt failed (or timeout, which is never retried)
        if (!ctx.closed) {
          this.safeEmit('tile.failed', {
            tileId: job.tileId,
            row: job.row,
            col: job.col,
            error: lastError.message,
          })
        }

        const result: TileJobResult<T> = {
          tileId: job.tileId,
          row: job.row,
          col: job.col,
          success: false,
          error: lastError.message,
          exception: lastError,
        }
        this.recordResult(ctx, result, false, job, totalCount, startTime)
        return result
      } finally {
        totalSignal.removeEventListener('abort', totalAbortHandler)
      }
    }

    // Should be unreachable, but TypeScript needs it
    const result: TileJobResult<T> = {
      tileId: job.tileId,
      row: job.row,
      col: job.col,
      success: false,
      error: lastError?.message ?? 'Unknown error',
      exception: lastError,
    }
    this.recordResult(ctx, result, false, job, totalCount, startTime)
    return result
  }

  /**
   * Record a tile result into the execution context (if not closed).
   * Also emits progress callback.
   */
  private recordResult(
    ctx: ExecutionContext<T>,
    result: TileJobResult<T>,
    success: boolean,
    job: TileJob<T>,
    totalCount: number,
    startTime: number,
  ): void {
    if (ctx.closed) return

    if (success) {
      ctx.completedCount++
    } else {
      ctx.failedCount++
    }
    ctx.collectedResults.push(result)

    this.safeEmitProgress(
      job,
      success ? 'completed' : 'failed',
      ctx.completedCount,
      ctx.failedCount,
      totalCount,
      startTime,
    )
  }

  /**
   * Compute retry delay with exponential backoff + jitter.
   *
   * delay = min(cap, base * 2^attempt) * random(0.5, 1.0)
   */
  private computeRetryDelay(attempt: number): number {
    const exponential = Math.min(this.retryBackoffCapMs, this.retryBackoffBaseMs * 2 ** attempt)
    const jitter = 0.5 + Math.random() * 0.5
    return exponential * jitter
  }

  /**
   * Emit a mitt event, catching any exceptions thrown by listeners.
   * Observer errors must not affect tile execution semantics.
   */
  private safeEmit<K extends keyof TileEvents>(event: K, data: TileEvents[K]): void {
    try {
      this.emitter.emit(event, data)
    } catch {
      // Swallow observer errors -- they should never affect execution
    }
  }

  /**
   * Emit progress via callback (best-effort).
   *
   * `finishedCount` tracks how many tiles have reached a terminal state
   * (completed + failed), while `status` indicates the individual tile's outcome.
   *
   * Catches any exceptions thrown by the callback so observer errors
   * never change tile execution semantics.
   */
  private safeEmitProgress(
    job: TileJob<T>,
    status: 'completed' | 'failed',
    completed: number,
    failed: number,
    total: number,
    startTime: number,
  ): void {
    if (!this.onProgress) return

    try {
      const progress: TileProgress = {
        tileId: job.tileId,
        row: job.row,
        col: job.col,
        status,
        completedCount: completed,
        totalCount: total,
        finishedCount: completed + failed,
        elapsedTime: (performance.now() - startTime) / 1000,
      }
      this.onProgress(progress)
    } catch {
      // Swallow observer errors -- they should never affect execution
    }
  }
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

/** Sleep for the given number of milliseconds. */
function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms))
}

/**
 * Race a promise against a timeout. If the timeout fires first, the returned
 * promise rejects with a `TileTimeoutError`. This enforces hard timeouts
 * even when the underlying promise ignores cancellation signals.
 */
function raceTimeout<T>(promise: Promise<T>, ms: number, message: string): Promise<T> {
  return new Promise<T>((resolve, reject) => {
    const timeoutId = setTimeout(() => reject(new TileTimeoutError(message)), ms)
    promise.then(
      (value) => {
        clearTimeout(timeoutId)
        resolve(value)
      },
      (error) => {
        clearTimeout(timeoutId)
        reject(error)
      },
    )
  })
}
