/**
 * GeoJSON polygon validation for tiling operations.
 *
 * Validates GeoJSON Polygon objects and normalizes winding order.
 * All geometry computations use the convention x=longitude, y=latitude,
 * consistent with GeoJSON coordinate order [lon, lat].
 */

import { PolygonValidationError } from '../errors'
import type { GeoJSONPolygon } from './types'

type Position = readonly [number, number, ...number[]]
type Edge = readonly [readonly [number, number], readonly [number, number]]

/**
 * Validate and normalize a GeoJSON Polygon.
 *
 * Validation chain:
 * 1. GeoJSON format (must be an object with 'type' and 'coordinates')
 * 2. type == "Polygon"
 * 3. Single ring (len(coordinates) == 1)
 * 4. >= 4 positions (3 unique vertices + closing vertex)
 * 5. Ring closed (first == last)
 * 6. Coordinate range: lon in [-180, 180], lat in [-90, 90]
 * 7. Self-intersection check (O(n^2) edge pairs)
 * 8. Winding order normalization (CCW exterior via shoelace, x=lon y=lat)
 *
 * @param geojson - A GeoJSON-like object to validate.
 * @returns A validated GeoJSONPolygon with CCW winding order.
 * @throws PolygonValidationError if any validation step fails.
 *
 * @example
 * ```ts
 * const polygon = validatePolygon({
 *   type: 'Polygon',
 *   coordinates: [[[13.39, 52.51], [13.4, 52.51], [13.4, 52.52], [13.39, 52.52], [13.39, 52.51]]],
 * })
 * ```
 */
export function validatePolygon(geojson: unknown): GeoJSONPolygon {
  // 1. GeoJSON format
  if (typeof geojson !== 'object' || geojson === null || Array.isArray(geojson)) {
    throw new PolygonValidationError(
      `Polygon must be an object, got ${Array.isArray(geojson) ? 'array' : typeof geojson}`,
    )
  }

  const obj = geojson as Record<string, unknown>

  if (!('type' in obj)) {
    throw new PolygonValidationError("Missing 'type' field in GeoJSON object")
  }

  if (!('coordinates' in obj)) {
    throw new PolygonValidationError("Missing 'coordinates' field in GeoJSON object")
  }

  // 2. type == "Polygon"
  if (obj.type !== 'Polygon') {
    throw new PolygonValidationError(
      `Expected type 'Polygon', got '${String(obj.type)}'. MultiPolygon and other types are not supported.`,
    )
  }

  const coordinates = obj.coordinates
  if (!Array.isArray(coordinates)) {
    throw new PolygonValidationError('Coordinates must be a list of rings')
  }

  // 3. Single ring (no holes)
  if (coordinates.length !== 1) {
    throw new PolygonValidationError(
      `Only single-ring polygons are supported (no holes). Got ${coordinates.length} ring(s).`,
    )
  }

  const ring = coordinates[0] as unknown[]
  if (!Array.isArray(ring)) {
    throw new PolygonValidationError('Ring must be a list of [lon, lat] positions')
  }

  // 4. >= 4 positions (3 unique + close)
  if (ring.length < 4) {
    throw new PolygonValidationError(
      `Ring must have at least 4 positions (3 unique vertices + closing vertex), got ${ring.length}`,
    )
  }

  // Validate each position is [lon, lat]
  for (let i = 0; i < ring.length; i++) {
    const pos = ring[i]
    if (!Array.isArray(pos) || pos.length < 2) {
      throw new PolygonValidationError(
        `Position ${i} must be a [lon, lat] array, got ${JSON.stringify(pos)}`,
      )
    }
  }

  const positions = ring as Position[]

  // 5. Ring closed (exact equality, matching Python's `first != last` check
  // in `tiling/validation.py:123`). Float epsilon tolerance was a TS-only
  // addition that silently accepted polygons Python rejects.
  const first = positions[0]
  const last = positions[positions.length - 1]
  if (first[0] !== last[0] || first[1] !== last[1]) {
    throw new PolygonValidationError(
      `Ring is not closed: first position [${first[0]}, ${first[1]}] != last position [${last[0]}, ${last[1]}]`,
    )
  }

  // 6. Coordinate range validation
  for (let i = 0; i < positions.length; i++) {
    const lon = positions[i][0]
    const lat = positions[i][1]
    if (lon < -180 || lon > 180) {
      throw new PolygonValidationError(`Position ${i}: longitude ${lon} out of range [-180, 180]`)
    }
    if (lat < -90 || lat > 90) {
      throw new PolygonValidationError(`Position ${i}: latitude ${lat} out of range [-90, 90]`)
    }
  }

  // 7. Self-intersection check
  const edges = ringToEdges(positions)
  checkSelfIntersection(edges)

  // 8. Winding order normalization (CCW in x=lon, y=lat space) +
  //    zero-area guard. Mirrors Python `tiling/validation.py:148`.
  const area = signedArea(positions)
  if (area === 0) {
    throw new PolygonValidationError(
      'Polygon has zero area (collinear or duplicate vertices)',
    )
  }
  if (area < 0) {
    // CW orientation, reverse to make CCW
    const reversedRing = [...positions].reverse() as Position[]
    return {
      type: 'Polygon',
      coordinates: [reversedRing],
    }
  }

  return {
    type: 'Polygon',
    coordinates: [positions],
  }
}

// ---------------------------------------------------------------------------
// Internal helpers
// ---------------------------------------------------------------------------

/**
 * Convert a closed ring to a list of edge tuples (start, end).
 * Uses unique vertices (excludes the closing duplicate).
 * Each tuple element is [lon, lat] = [x, y].
 */
function ringToEdges(ring: readonly Position[]): Edge[] {
  const n = ring.length - 1 // exclude closing vertex
  const edges: Edge[] = []
  for (let i = 0; i < n; i++) {
    const j = (i + 1) % n
    edges.push([
      [ring[i][0], ring[i][1]],
      [ring[j][0], ring[j][1]],
    ])
  }
  return edges
}

/**
 * Check for self-intersecting edges via O(n^2) brute force.
 * Adjacent edges share a vertex and are skipped.
 */
function checkSelfIntersection(edges: Edge[]): void {
  const n = edges.length
  for (let i = 0; i < n; i++) {
    for (let j = i + 2; j < n; j++) {
      // Skip adjacent edges (they share a vertex)
      if (i === 0 && j === n - 1) {
        continue
      }
      const [a, b] = edges[i]
      const [c, d] = edges[j]
      if (segmentsIntersectProper(a, b, c, d)) {
        throw new PolygonValidationError(
          `Polygon has self-intersection between edge ${i} ([${a}] -> [${b}]) and edge ${j} ([${c}] -> [${d}])`,
        )
      }
    }
  }
}

/** 2D cross product of vectors (O->A) x (O->B). */
function cross(ox: number, oy: number, ax: number, ay: number, bx: number, by: number): number {
  return (ax - ox) * (by - oy) - (ay - oy) * (bx - ox)
}

/**
 * Check if point (qx, qy) lies on segment (px, py)-(rx, ry).
 * Assumes the three points are collinear.
 */
function onSegment(
  px: number,
  py: number,
  qx: number,
  qy: number,
  rx: number,
  ry: number,
): boolean {
  return (
    Math.min(px, rx) <= qx &&
    qx <= Math.max(px, rx) &&
    Math.min(py, ry) <= qy &&
    qy <= Math.max(py, ry)
  )
}

/**
 * Check if line segments AB and CD properly intersect.
 *
 * Returns true if the segments cross each other (not just touch
 * at shared endpoints, which is handled by adjacency filtering).
 */
function segmentsIntersectProper(
  a: readonly [number, number],
  b: readonly [number, number],
  c: readonly [number, number],
  d: readonly [number, number],
): boolean {
  const d1 = cross(a[0], a[1], b[0], b[1], c[0], c[1])
  const d2 = cross(a[0], a[1], b[0], b[1], d[0], d[1])
  const d3 = cross(c[0], c[1], d[0], d[1], a[0], a[1])
  const d4 = cross(c[0], c[1], d[0], d[1], b[0], b[1])

  if (((d1 > 0 && d2 < 0) || (d1 < 0 && d2 > 0)) && ((d3 > 0 && d4 < 0) || (d3 < 0 && d4 > 0))) {
    return true
  }

  // Collinear overlap cases
  if (d1 === 0 && onSegment(a[0], a[1], c[0], c[1], b[0], b[1])) return true
  if (d2 === 0 && onSegment(a[0], a[1], d[0], d[1], b[0], b[1])) return true
  if (d3 === 0 && onSegment(c[0], c[1], a[0], a[1], d[0], d[1])) return true
  if (d4 === 0 && onSegment(c[0], c[1], b[0], b[1], d[0], d[1])) return true

  return false
}

/**
 * Compute the signed area of a ring using the shoelace formula.
 *
 * Uses x=lon, y=lat convention consistent with GeoJSON.
 * Positive area = counter-clockwise (CCW).
 * Negative area = clockwise (CW).
 *
 * The closing vertex is excluded from the summation since
 * it duplicates the first vertex.
 */
function signedArea(ring: readonly Position[]): number {
  const n = ring.length - 1 // exclude closing vertex
  let area = 0
  for (let i = 0; i < n; i++) {
    const j = (i + 1) % n
    const xi = ring[i][0]
    const yi = ring[i][1]
    const xj = ring[j][0]
    const yj = ring[j][1]
    area += xi * yj - xj * yi
  }
  return area / 2.0
}
